import os
import time
import json
import requests
from dotenv import load_dotenv

load_dotenv()

class AIApiClient:
    """Reusable API client with retry, timeout, and error handling."""

    def __init__(self, base_url: str, api_key: str | None = None,
                 extra_headers: dict | None = None):
        self.base_url = base_url.rstrip('/')
        self.session = requests.Session()
        self.session.headers.update({
            'Content-Type': 'application/json',
            'Accept': 'application/json',
            'User-Agent': 'AIApp/1.0',
        })
        if api_key:
            self.session.headers['Authorization'] = f'Bearer {api_key}'
        if extra_headers:
            self.session.headers.update(extra_headers)

    def post(self, path: str, body: dict, timeout: int = 30,
             max_retries: int = 3) -> dict | None:
        url = f"{self.base_url}/{path.lstrip('/')}"

        for attempt in range(max_retries + 1):
            try:
                response = self.session.post(url, json=body, timeout=timeout)

                if response.status_code == 200:
                    return response.json()

                # Client errors: fix your code, don't retry
                if response.status_code in (400, 401, 403, 404, 422):
                    error = response.json().get('error', {})
                    print(f"❌ {response.status_code}: {error.get('message', response.text)}")
                    return None

                # Rate limit: respect Retry-After header
                if response.status_code == 429:
                    wait = float(response.headers.get('Retry-After', 2 ** attempt))
                    print(f"⏳ Rate limited — waiting {wait:.0f}s (attempt {attempt+1})")
                    time.sleep(wait)
                    continue

                # Server errors: retry with exponential backoff
                if response.status_code >= 500:
                    if attempt < max_retries:
                        wait = 2 ** attempt
                        print(f"🔄 Server error {response.status_code} — retry in {wait}s")
                        time.sleep(wait)
                        continue

                return None

            except requests.Timeout:
                if attempt < max_retries:
                    print(f"⏱️  Timeout — retry {attempt+1}")
                    time.sleep(2 ** attempt)
                else:
                    print("❌ All retries exhausted (timeout)")
                    return None
            except requests.ConnectionError as e:
                print(f"🔌 Connection error: {e}")
                return None

        return None


def demo_public_api():
    """Demo using httpbin.org — no API key needed."""
    client = AIApiClient(base_url="https://httpbin.org")

    # Test POST with JSON body
    result = client.post(
        path="/post",
        body={"model": "test", "messages": [{"role": "user", "content": "hello"}]},
    )
    if result:
        print("✅ POST success")
        print(f"   Sent data: {json.dumps(result.get('json', {}), indent=2)[:200]}")


def demo_anthropic_format():
    """Show how to call Anthropic with the correct headers."""
    api_key = os.getenv('ANTHROPIC_API_KEY')
    if not api_key:
        print("⚠️  No ANTHROPIC_API_KEY found — showing request structure only")
        print("Headers needed:")
        print("  x-api-key: sk-ant-...")
        print("  anthropic-version: 2023-06-01")
        print("  content-type: application/json")
        print("Body:")
        body = {
            "model": "claude-haiku-4-5-20251001",
            "max_tokens": 256,
            "messages": [{"role": "user", "content": "What is 2+2?"}]
        }
        print(json.dumps(body, indent=2))
        return

    client = AIApiClient(
        base_url="https://api.anthropic.com",
        api_key=None,  # Anthropic uses x-api-key, not Bearer
        extra_headers={
            "x-api-key": api_key,
            "anthropic-version": "2023-06-01",
        }
    )
    result = client.post(
        path="/v1/messages",
        body={
            "model": "claude-haiku-4-5-20251001",
            "max_tokens": 64,
            "messages": [{"role": "user", "content": "Say hello in 5 words"}]
        }
    )
    if result:
        print(f"Claude says: {result['content'][0]['text']}")
        print(f"Tokens used: {result['usage']}")


if __name__ == '__main__':
    print("Demo 1: Public API")
    demo_public_api()
    print("\nDemo 2: Anthropic API format")
    demo_anthropic_format()
